class Solution {
    private static final int MOD = (int) (1e9 + 7);
    public int numberOfStableArrays(int zero, int one, int limit) {
        long[][][] dp = new long[limit + 1][zero + 1][one + 1];
        dp[1][1][0] = 1;
        dp[1][0][1] = 1;
        for (int l = 2; l <= limit; l++) {
            for (int z = 1; z <= zero; z++) {
                for (int o = 1; o <= one; o++) {
                    dp[l][z][o] = (dp[l - 1][z - 1][o] + dp[l - 1][z][o - 1]) % MOD;
                }
            }
        }
        long res = 0;
        for (int l = 1; l <= limit; l++) {
            res = (res + dp[l][zero][one]) % MOD;
        }
        return (int) res;
    }
}
